#!/usr/bin/env bash
# Regenerate the hydra-bench package on demand.
#
# hydra-bench owns the synthetic inference benchmark workloads (hydra.bench.*).
# These modules are deliberately stress-shaped (deep curried cascades, wide
# records, branchy DAGs) and are NOT regenerated by the default bin/sync.sh.
# Run this script before bin/run-inference-bench.sh whenever the bench source
# modules have changed or you've added a host to the comparison.
#
# Usage:
#   bin/sync-bench.sh                       # Default hosts: haskell,java,python
#   bin/sync-bench.sh --hosts H,...         # Explicit comma-separated hosts
#   bin/sync-bench.sh --hosts all           # Same as default
#   bin/sync-bench.sh --help
#
# Note: Lisp hosts (Clojure, Common Lisp, Scheme, Emacs Lisp) are intentionally
# NOT regenerated by default. Their coders are very slow on the deep
# walker-cascade pattern; the inference benchmark does not yet drive them.
# Pass --hosts clojure (etc.) explicitly to regenerate anyway.

set -euo pipefail

SCRIPT_DIR="$( cd "$( dirname "${BASH_SOURCE[0]}" )" && pwd )"
HYDRA_ROOT="$( cd "$SCRIPT_DIR/.." && pwd )"
HYDRA_HASKELL_DIR="$HYDRA_ROOT/heads/haskell"

DEFAULT_HOSTS="haskell,java,python"
HOSTS="$DEFAULT_HOSTS"

while [ $# -gt 0 ]; do
    case "$1" in
        --hosts) HOSTS="$2"; shift 2 ;;
        --hosts=*) HOSTS="${1#--hosts=}"; shift ;;
        --help|-h)
            sed -n '2,/^$/p' "$0" | sed 's/^# \{0,1\}//'
            exit 0
            ;;
        *)
            echo "Unknown argument: $1" >&2
            exit 1
            ;;
    esac
done

# Expand 'all' to the default benchmark-capable hosts.
if [ "$HOSTS" = "all" ]; then
    HOSTS="$DEFAULT_HOSTS"
fi

echo "=== sync-bench: regenerating hydra-bench for hosts: $HOSTS ==="

# Phase 1a: regenerate dist/json/ with --include-bench so the hydra-bench
# package's JSON and manifest are written.
echo ""
echo "--- Phase 1: DSL → JSON + per-package manifests (with --include-bench) ---"
(cd "$HYDRA_HASKELL_DIR" && \
    stack build hydra:exe:update-json-main hydra:exe:update-json-manifest && \
    stack exec update-json-main -- --include-bench && \
    stack exec update-json-manifest -- --include-bench)

# Phase 2: per-host assemble-distribution.sh for hydra-bench.
IFS=',' read -ra HOST_ARR <<< "$HOSTS"
for L in "${HOST_ARR[@]}"; do
    echo ""
    echo "--- hydra-bench -> $L ---"
    case "$L" in
        haskell)
            "$HYDRA_HASKELL_DIR/bin/assemble-distribution.sh" hydra-bench
            ;;
        java|python|scala)
            "$HYDRA_ROOT/heads/$L/bin/assemble-distribution.sh" hydra-bench
            ;;
        clojure|scheme|common-lisp|emacs-lisp)
            "$HYDRA_ROOT/heads/lisp/bin/assemble-distribution.sh" hydra-bench "$L"
            ;;
        *)
            echo "Unknown host: $L" >&2
            exit 1
            ;;
    esac
done

echo ""
echo "=== sync-bench complete ==="
